import json
import hashlib
import hmac
import os
from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Configuration
WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET')
ALLOWED_PARTNERS = set(os.environ.get('ALLOWED_PARTNERS', '').split(','))

def validate_signature(request):
    """Validate webhook signature"""
    signature = request.headers.get('X-Signature')
    if not signature:
        return False
    
    payload = request.get_data()
    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode(),
        payload,
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def validate_partner(request):
    """Validate partner is allowed"""
    partner_id = request.headers.get('X-Partner-ID')
    return partner_id in ALLOWED_PARTNERS

def webhook_required(f):
    """Decorator to validate webhook requests"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not validate_signature(request):
            return jsonify({'error': 'Invalid signature'}), 401
        
        if not validate_partner(request):
            return jsonify({'error': 'Unauthorized partner'}), 403
            
        return f(*args, **kwargs)
    return decorated_function

@app.route('/webhook/payment', methods=['POST'])
@webhook_required
def payment_webhook():
    """Handle payment webhook events"""
    try:
        data = request.get_json()
        
        # Validate required fields
        required_fields = ['event_type', 'payment_id', 'amount', 'currency']
        for field in required_fields:
            if field not in data:
                return jsonify({'error': f'Missing required field: {field}'}), 400
        
        # Process webhook event
        event_type = data['event_type']
        payment_id = data['payment_id']
        
        # Log the event (ensure logging is secure)
        print(f"Processing {event_type} for payment {payment_id}")
        
        # Your business logic here
        # Example: Update database, send notifications, etc.
        
        return jsonify({'status': 'success', 'message': 'Webhook processed'}), 200
        
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

